  coverUrl: string;
  description: string;
}

export type ArticleLayout = 'columna-izquierda' | 'columna-derecha' | 'columna-centro' | 'media-hoja' | 'hoja-completa' | 'columna-izquierda-centrada';

export interface CoverStory {
    headline: string;
    subtitle: string;
    imageUrl?: string;
}

export interface OddPage {
    type: 'odd';
    id: string;
    headline: string;
