import React, { useState, useEffect } from 'react';
import { WEEKLY_EDITION_CONTENT } from '../data/weeklyContent.ts';
import type { Page, OddPage, EvenPage } from '../types.ts';
import IndexPage from './IndexPage.tsx';

const Magazine: React.FC = () => {
  const [currentPageIndex, setCurrentPageIndex] = useState(0); // 0: Cover, 1: Index, 2+: Pages
  const { cover, pages } = WEEKLY_EDITION_CONTENT;

  // Total de "vistas": Portada + Índice + Páginas
  const totalViews = 2 + pages.length;

  const goToNextPage = () => {
    if (currentPageIndex < totalViews - 1) setCurrentPageIndex(prev => prev + 1);
  };

  const goToPrevPage = () => {
    if (currentPageIndex > 0) setCurrentPageIndex(prev => prev - 1);
  };

  const navigateToPage = (index: number) => {
    setCurrentPageIndex(index);
  };

  // Preparar artículos para el índice
  const indexArticles = pages
    .filter((p): p is OddPage => p.type === 'odd')
    .map((p, idx) => ({
      ...p,
      originalIndex: pages.indexOf(p),
      pageNumber: idx + 1
    }));

  return (
    <div className="w-full max-w-5xl mx-auto font-typewriter shadow-[0_0_50px_rgba(0,0,0,0.1)] dark:shadow-none border-x-4 border-double border-stone-800 dark:border-stone-600 bg-[#fdfaf4] dark:bg-stone-900 min-h-[80vh] flex flex-col relative overflow-hidden">

      {/* Navegación Superior */}
      <div className="flex justify-between items-center p-4 border-b-2 border-stone-800 dark:border-stone-600 bg-stone-100 dark:bg-stone-800 z-10 text-xs font-black uppercase tracking-widest">
        <button 
          onClick={goToPrevPage} 
          disabled={currentPageIndex === 0}
          className="hover:text-red-700 disabled:opacity-20 transition-colors"
        >
          &larr; Anterior
        </button>
        <div className="text-center">
          Edición Semanal • {currentPageIndex === 0 ? "Portada" : currentPageIndex === 1 ? "Índice" : `Pág. ${currentPageIndex - 1}`}
        </div>
        <button 
          onClick={goToNextPage} 
          disabled={currentPageIndex === totalViews - 1}
          className="hover:text-red-700 disabled:opacity-20 transition-colors"
        >
          Siguiente &rarr;
        </button>
      </div>

      {/* Contenedor de Páginas */}
      <div className="flex-grow flex flex-col relative">
        {currentPageIndex === 0 && (
          <div className="animate-fade-in p-8 md:p-12 text-center flex flex-col items-center justify-center flex-grow">
            <h4 className="text-red-700 font-bold mb-4 tracking-[0.3em] uppercase text-sm border-y border-red-700 py-1">Exclusivo de El Nexo Digital</h4>
            <h1 className="text-6xl md:text-8xl newspaper-title leading-tight mb-6">{cover.headline}</h1>
            <p className="text-xl md:text-2xl italic text-stone-600 dark:text-stone-400 max-w-2xl mb-10">{cover.subtitle}</p>
            {cover.imageUrl && (
              <div className="w-full aspect-video rounded overflow-hidden shadow-2xl border-4 border-stone-800 dark:border-stone-200">
                <img src={cover.imageUrl} alt="Portada" className="w-full h-full object-cover" />
              </div>
            )}
            <button 
              onClick={goToNextPage}
              className="mt-12 px-10 py-4 bg-stone-900 text-white dark:bg-stone-100 dark:text-stone-900 font-bold uppercase tracking-tighter hover:bg-red-700 transition-colors"
            >
              Abrir Edición
            </button>
          </div>
        )}

        {currentPageIndex === 1 && (
          <div className="animate-fade-in flex-grow">
            <IndexPage 
              articles={indexArticles} 
              onNavigate={(mobile, desktop) => navigateToPage(mobile)} 
            />
          </div>
        )}

        {currentPageIndex >= 2 && (
          <PageRenderer page={pages[currentPageIndex - 2]} />
        )}
      </div>

      {/* Indicador de Progreso (Scrollbar custom) */}
      <div className="h-1 bg-stone-200 dark:bg-stone-800 w-full overflow-hidden">
        <div 
          className="h-full bg-red-700 transition-all duration-500" 
          style={{ width: `${((currentPageIndex + 1) / totalViews) * 100}%` }}
        />
      </div>
    </div>
  );
};

const PageRenderer = ({ page }: { page: Page }) => {
  if (page.type === 'even') {
    return (
      <div className="animate-fade-in w-full h-full relative flex flex-col items-center justify-center p-8">
        <div className="w-full h-full max-h-[70vh] rounded overflow-hidden border-8 border-white shadow-2xl rotate-1">
          <img src={page.imageUrl} alt="Arte" className="w-full h-full object-cover" style={{ objectPosition: page.objectPosition || 'center' }} />
        </div>
        {page.headline && (
           <div className="absolute bottom-12 bg-black text-white p-4 max-w-md transform -rotate-1 shadow-xl">
              <h2 className="text-2xl font-bold uppercase leading-none">{page.headline}</h2>
           </div>
        )}
      </div>
    );
  }

  // Render para OddPage (Investigaciones)
  return (
    <article className="animate-fade-in p-8 md:p-16 flex-grow flex flex-col">
      <header className="mb-8 pb-6 border-b-2 border-stone-300 dark:border-stone-700">
        <span className="text-red-700 font-black uppercase text-xs tracking-widest mb-2 block">{page.category}</span>
        <h2 className="text-4xl md:text-5xl font-bold leading-tight mb-4" style={{ fontFamily: "'Playfair Display', serif" }}>{page.headline}</h2>
        {page.subtitle && <p className="text-xl italic text-stone-500">{page.subtitle}</p>}
      </header>

      <div className="flex-grow">
        {renderLayout(page)}
      </div>

      {page.sources && page.sources.length > 0 && (
        <footer className="mt-12 pt-4 border-t border-stone-200 text-[10px] text-stone-400 italic">
          Fuentes: {page.sources.join(', ')}
        </footer>
      )}
    </article>
  );
};

const renderLayout = (page: OddPage) => {
  const contentParagraphs = page.content.split('\n\n');

  switch (page.layout) {
    case 'hoja-completa':
      return (
        <div className="columns-1 md:columns-2 gap-8 text-lg leading-relaxed">
          {contentParagraphs.map((p, i) => (
            <p key={i} className={`mb-4 ${i === 0 ? 'first-letter:text-5xl first-letter:font-bold first-letter:float-left first-letter:mr-2 first-letter:mt-1 first-letter:text-red-700' : ''}`}>
              {p}
            </p>
          ))}
        </div>
      );
    case 'columna-izquierda':
      return (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
          <div className="md:col-span-1 border-r border-stone-300 pr-8">
             <div className="bg-stone-200 p-4 mb-6">
                <p className="font-bold italic text-sm">"La verdad no es lo que parece en la superficie, sino lo que reside en el nexo."</p>
             </div>
             <p className="text-sm leading-relaxed">{contentParagraphs[0]}</p>
          </div>
          <div className="md:col-span-2 columns-1 gap-8 text-lg leading-relaxed">
             {contentParagraphs.slice(1).map((p, i) => <p key={i} className="mb-4">{p}</p>)}
          </div>
        </div>
      );
    default:
      return <div className="text-lg leading-relaxed">{page.content}</div>;
  }
};

export default Magazine;

