                <span className="absolute -top-1 -right-1 bg-red-600 text-white text-[10px] font-bold w-5 h-5 rounded-full flex items-center justify-center border-2 border-white">
                  {props.notesCount}
                </span>
              )}
            </button>
          )}

          {props.onAdminAuthRequest && (
            <button 
              onClick={props.onAdminAuthRequest}
              className="w-10 h-10 rounded-full bg-stone-200 border border-stone-800 flex items-center justify-center shadow-sm hover:bg-stone-300 transition-colors"
              title="Administrar notas"
            >
              <span className="text-sm">🔑</span>
            </button>
          )}
        </div>

        {props.showPodcastButton && (
          <FloatingPodcastButton onClick={props.onPodcastButtonClick} />
        )}

        {/* Fixed: Added Protected Content / Mecenas button */}
        {props.onProtectedButtonClick && (
          <button 
            onClick={props.onProtectedButtonClick}
            className="group relative w-24 h-24 rounded-full shadow-lg transition-all hover:scale-105 bg-stone-100 border-2 border-stone-800 flex flex-col items-center justify-center p-2"
